{{#if:{{{sortable|}}}
|<span style="display:none; speak:none;">{{padleft:{{{sort_date|{{{sortdate|{{{sort-date|{{{single|{{{pre-date|{{{predate|{{{pre_date|{{{1|{{{2|{{{post-date|{{{postdate|{{{post_date|}}}}}}}}}}}}}}}}}}}}}}}}}}}}}}}}}}}}|4|0}}</span>
}}<span style="white-space:nowrap;"><!--
-->{{#if:{{{label|}}}
   |{{{label}}}{{#if:{{{wrap|}}}|{{wbr}}}}
   |{{#switch:{{{show|{{{link|{{{lk|}}}}}}}}}
    |no|off|n|false|0|none = {{#if:{{{cap|}}}|R|r}}.
    |link|yes|on|y|true|1 = [[:en:reign|{{#if:{{{cap|}}}|R|r}}.]]
    |word = {{#if:{{{cap|}}}|R|r}}eigned
    |colon = {{#if:{{{cap|}}}|R|r}}eign:
    |lword = [[:en:reign|{{#if:{{{cap|}}}|R|r}}eigned]]
    |lcolon = [[:en:reign|{{#if:{{{cap|}}}|R|r}}eign]]:
    |blank =
    |abbr|#default = {{Abbr|{{#if:{{{cap|}}}|R|r}}.|reigned}}
    }}
   }}<!--
-->{{#ifeq:{{{show|{{{link|{{{lk|}}}}}}}}}|blank
   |<!--nothing-->
   |{{#if:{{{pre-date|}}}{{{predate|}}}{{{pre_date}}}{{{1|}}}{{{2|}}}|&{{#switch:{{{show|{{{link|{{{lk|}}}}}}}}}
    |word|colon|lword|lcolon = nbsp
    |#default = {{#if:{{{label|}}}|nbsp|thinsp}}}};
    }}
   }}<!--
-->{{#if:{{{pre-date|}}}{{{predate|}}}{{{pre_date|}}}|{{{pre-date|{{{pre|{{{pre_date}}}}}}}}},&nbsp;{{#if:{{{wrap|}}}|{{wbr}}}}}}<!--
-->{{#if:{{{1|}}}|{{trim|{{{1}}}}}}}<!--
-->{{#if:{{{2|}}}
   |{{#if:{{{1|}}}||?}}<!--
  -->{{#ifeq:{{#invoke:String |find |source={{trim|{{{1|}}}}}{{trim|{{{2|}}}}} |target=%s |plain=false }} | 0
     |–{{trim|{{{2}}}}}
     |&nbsp;–&nbsp;{{trim|{{{2}}}}}
     }}<!--
  -->{{#if:{{{mid-date|}}}{{{middate|}}}{{{mid_date|}}}
     |,&nbsp;{{#if:{{{wrap|}}}|{{wbr}}}}{{{mid-date|{{{middate|{{{mid_date}}}}}}}}}}}<!--
  -->{{#if:{{{3|}}}{{{4|}}}
     |,&nbsp;{{#if:{{{wrap|}}}|{{wbr}}}}{{#if:{{{3|}}}|{{trim|{{{3}}}}}|?}}<!--
   -->{{#ifeq:{{#invoke:String |find |source={{trim|{{{3|}}}}}{{trim|{{{4|}}}}} |target=%s |plain=false }} | 0
      |–{{trim|{{{4}}}}}
      |&nbsp;–&nbsp;{{trim|{{{4}}}}}
      }}
     }}
   |{{#if:{{{1|}}}|–&nbsp;}}
   }}<!--
-->{{#if:{{{single|}}}{{{post-date|}}}{{{postdate|}}}{{{post_date|}}}
   |{{#if:{{{1|}}}{{{2|}}}|,&nbsp;}}{{#if:{{{wrap|}}}|{{wbr}}}}{{{single|{{{post-date|{{{postdate|{{{post_date}}}}}}}}}}}}
   }}<!--
-->{{#if:{{{era|}}}|&nbsp;{{{era}}}}}<!--
--></span><noinclude>
{{Documentation}}[[Category:Templates with Documentation template]]
</noinclude>
[[Category:Templates]]

